import{_ as a,c as i,o as t,ah as e}from"./chunks/framework.C-x9UAyH.js";const u=JSON.parse('{"title":"Comandos Cron y Rsync","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/comandos_cron_y_rsync.md","filePath":"aws/comandos_cron_y_rsync.md","lastUpdated":1760459112000}'),o={name:"aws/comandos_cron_y_rsync.md"};function n(l,s,r,h,d,p){return t(),i("div",null,[...s[0]||(s[0]=[e('<h1 id="comandos-cron-y-rsync" tabindex="-1">Comandos Cron y Rsync <a class="header-anchor" href="#comandos-cron-y-rsync" aria-label="Permalink to &quot;Comandos Cron y Rsync&quot;">​</a></h1><h2 id="programar-tareas-automaticas" tabindex="-1">Programar tareas automáticas <a class="header-anchor" href="#programar-tareas-automaticas" aria-label="Permalink to &quot;Programar tareas automáticas&quot;">​</a></h2><p>cron es un sistema para programar tareas automáticas en Linux, ejecutando comandos o scripts en momentos específicos (por ejemplo, cada hora, día, etc.). Las tareas se definen en un archivo llamado crontab.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cron</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [opciones]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Opciones</th><th>Resultado</th></tr></thead><tbody><tr><td>-e</td><td>Edita el archivo crontab del usuario actual.</td></tr><tr><td>-l</td><td>Lista las tareas programadas.</td></tr><tr><td>-r</td><td>Elimina el crontab del usuario.</td></tr></tbody></table><ul><li>Formato de una entrada en crontab:</li></ul><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>* * * * * /ruta/al/script.sh</span></span></code></pre></div><p>Los cinco asteriscos representan: minuto, hora, día del mes, mes, día de la semana. Un asterisco (*) significa &quot;cada&quot;.</p><h3 id="ejemplo" tabindex="-1">Ejemplo <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo&quot;">​</a></h3><ol><li>Ejecutar un script cada día a las 2 a.m.</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">crontab</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span></span></code></pre></div><ul><li>Añadir al archivo crontab:</li></ul><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0 2 * * * /home/usuario/backup.sh</span></span></code></pre></div><ol start="2"><li>Ejecutar un comando cada 5 minutos</li></ol><ul><li>Escribe &quot;Hola&quot; en log.txt cada 5 minutos</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/5 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /usr/bin/echo </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hola&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /home/usuario/log.txt</span></span></code></pre></div><ol start="3"><li>Listar tareas programadas</li></ol><ul><li>Muestra el contenido del crontab del usuario actual</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">crontab</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span></code></pre></div><ol start="4"><li>Programar una tarea para un usuario específico</li></ol><ul><li>Edita el crontab del usuario &#39;juan&#39;</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> crontab</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> juan</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span></span></code></pre></div><h2 id="sincronizar-archivos-y-directorios" tabindex="-1">Sincronizar archivos y directorios <a class="header-anchor" href="#sincronizar-archivos-y-directorios" aria-label="Permalink to &quot;Sincronizar archivos y directorios&quot;">​</a></h2><p>rsync es una herramienta para sincronizar archivos y directorios entre dos ubicaciones (locales o remotas), optimizando la transferencia al copiar solo las diferencias.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [opciones] origen destino</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Opciones</th><th>Resultado</th></tr></thead><tbody><tr><td>-a</td><td>Modo archivo (preserva permisos, propietarios, enlaces, etc.).</td></tr><tr><td>-v</td><td>Modo detallado (muestra el progreso).</td></tr><tr><td>-r</td><td>Copia recursiva (incluye subdirectorios).</td></tr><tr><td>-z</td><td>Comprime datos durante la transferencia.</td></tr><tr><td>--delete</td><td>Elimina archivos en el destino que no están en el origen.</td></tr><tr><td>-e</td><td>Especifica el protocolo remoto (por ejemplo, SSH).</td></tr></tbody></table><h3 id="ejemplos" tabindex="-1">Ejemplos <a class="header-anchor" href="#ejemplos" aria-label="Permalink to &quot;Ejemplos&quot;">​</a></h3><ol><li>Sincronizar un directorio localmente</li></ol><ul><li>Copia el contenido de /home/usuario/fotos a /backups/fotos, preservando permisos y mostrando detalles.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/usuario/fotos</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backups/fotos</span></span></code></pre></div><ol start="2"><li>Sincronizar con un servidor remoto vía SSH</li></ol><ul><li>Sincroniza documentos con un servidor remoto, usando compresión (-z) y SSH.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/usuario/documentos</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usuario@servidor:/ruta/remota</span></span></code></pre></div><ol start="3"><li>Sincronizar eliminando archivos obsoletos</li></ol><ul><li>Sincroniza proyectos y elimina en /backups/proyectos cualquier archivo que no esté en el origen.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/usuario/proyectos</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backups/proyectos</span></span></code></pre></div><ol start="4"><li>Excluir archivos o directorios</li></ol><ul><li>Sincroniza todo menos los archivos con extensión .log</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --exclude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;*.log&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/usuario</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backups</span></span></code></pre></div><ol start="5"><li>Sincronización en seco (prueba sin cambios reales)</li></ol><ul><li>Muestra qué se sincronizaría sin realizar cambios.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/usuario</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backups</span></span></code></pre></div><h3 id="datos-sobre-rsync" tabindex="-1">Datos sobre rsync <a class="header-anchor" href="#datos-sobre-rsync" aria-label="Permalink to &quot;Datos sobre rsync&quot;">​</a></h3><ul><li>Es ideal para copias de seguridad o sincronización entre servidores.</li><li>Usa SSH para transferencias seguras a servidores remotos.</li><li>Verifica los permisos en el destino para evitar errores.</li></ul>',44)])])}const k=a(o,[["render",n]]);export{u as __pageData,k as default};
